#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long sum = 0; for (int i = 0; i < N; ++i) { int x; scanf("%d", &x); sum += x; }
        if (N == 1) printf("NO\n");
        else if (sum % 2 == 0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

