import sys
def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        total = 0
        for _ in range(N):
            total += int(next(it))
        if N == 1:
            out.append('NO')
        elif total % 2 == 0:
            out.append('YES')
        else:
            out.append('NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

